const body = $input.first().json.body || $input.first().json;
const requestId = body.request_id || '';
const accountName = body.account_name || '';
const isDone = (body.done === 'true' || body.done === true);

if (!isDone) {
  // Individual task received — store it
  return [{ json: {
    isDone: false,
    requestId,
    accountName,
    task: {
      Id: body.task_id || '',
      Subject: body.task_subject || '',
      Status: body.task_status || '',
      Priority: body.task_priority || '',
      ActivityDate: body.task_due_date || '',
      Description: body.task_description || '',
      Owner_Name: body.task_owner_name || '',
      Owner_Email: body.task_owner_email || '',
      Category: body.task_category || '',
      Duration: body.task_duration || '',
      Account_Name: body.task_account_name || '',
    }
  }}];
} else {
  // Done signal — time to render
  return [{ json: {
    isDone: true,
    requestId,
    accountName,
  }}];
}

const callbackData = $('Parse Callback').first().json;
const contextArr = $('Fetch Request Context').all().map(i => i.json);
const context = Array.isArray(contextArr[0]) ? contextArr[0][0] : contextArr[0];
const taskRows = $('Fetch All Tasks').all().map(i => i.json);
const allTaskRows = Array.isArray(taskRows[0]) ? taskRows[0] : taskRows;

let meta = context.context || {};
if (typeof meta === 'string') try { meta = JSON.parse(meta); } catch(e) { meta = {}; }

const tasks = allTaskRows.map(row => {
  try { return JSON.parse(row.draft_content || '{}'); } catch(e) { return {}; }
}).filter(t => t.Id);

const accountName = callbackData.accountName || meta.account_name || 'Account';
const isMyTasks = (accountName === 'My Tasks');
const channelId = meta.channel_id || '';
const messageTs = meta.message_ts || '';
const assistantName = meta.assistant_name || 'Aria';
const assistantEmoji = meta.assistant_emoji || ':robot_face:';

const openTasks = tasks.filter(t => t.Status !== 'Completed');
const completedTasks = tasks.filter(t => t.Status === 'Completed');

// Date helpers
const now = new Date();
const ptNow = new Date(now.toLocaleString('en-US', { timeZone: 'America/Los_Angeles' }));
const todayStr = ptNow.toISOString().split('T')[0];

function formatDate(dateStr) {
  if (!dateStr) return '';
  const d = new Date(dateStr + 'T12:00:00');
  return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
}

function daysUntil(dateStr) {
  if (!dateStr) return null;
  const due = new Date(dateStr + 'T00:00:00');
  const today = new Date(todayStr + 'T00:00:00');
  return Math.round((due - today) / 86400000);
}

function statusIndicator(dateStr) {
  const days = daysUntil(dateStr);
  if (days === null) return '';
  if (days < 0) return ':red_circle: ';
  if (days <= 7) return ':warning: ';
  return ':white_check_mark: ';
}

function dueLabel(dateStr) {
  const days = daysUntil(dateStr);
  const formatted = formatDate(dateStr);
  if (days === null) return '';
  if (days < -1) return `*Overdue* (${Math.abs(days)} days) \u2014 was ${formatted}`;
  if (days === -1) return `*Overdue* (yesterday)`;
  if (days === 0) return `*Due today*`;
  if (days === 1) return `Due tomorrow`;
  if (days <= 7) return `Due ${formatted} (this week)`;
  return `Due ${formatted}`;
}

// Categorize by urgency
const overdueTasks = openTasks.filter(t => daysUntil(t.ActivityDate) < 0);
const thisWeekTasks = openTasks.filter(t => { const d = daysUntil(t.ActivityDate); return d !== null && d >= 0 && d <= 7; });
const futureTasks = openTasks.filter(t => { const d = daysUntil(t.ActivityDate); return d === null || d > 7; });

const blocks = [];

// Header
blocks.push({
  type: "header",
  text: { type: "plain_text", text: isMyTasks ? "My Tasks" : (accountName + " \u2014 Tasks"), emoji: true }
});

// Summary line
const summaryParts = [];
summaryParts.push(`${openTasks.length} open`);
if (overdueTasks.length > 0) summaryParts.push(`:red_circle: ${overdueTasks.length} overdue`);
if (thisWeekTasks.length > 0) summaryParts.push(`:warning: ${thisWeekTasks.length} due this week`);
if (completedTasks.length > 0) summaryParts.push(`${completedTasks.length} completed`);

blocks.push({
  type: "context",
  elements: [{ type: "mrkdwn", text: summaryParts.join(' \u00b7 ') }]
});

// Helper to render a task section
function renderTasks(taskList, sectionLabel, maxItems) {
  if (taskList.length === 0) return;

  blocks.push({ type: "divider" });
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: `*${sectionLabel} (${taskList.length})*` }
  });

  // Sort by due date
  taskList.sort((a, b) => {
    const dA = daysUntil(a.ActivityDate);
    const dB = daysUntil(b.ActivityDate);
    return (dA === null ? 999 : dA) - (dB === null ? 999 : dB);
  });

  for (const t of taskList.slice(0, maxItems)) {
    const indicator = statusIndicator(t.ActivityDate);
    const due = dueLabel(t.ActivityDate);
    const owner = t.Owner_Name ? ` \u2014 _${t.Owner_Name}_` : '';
    const status = t.Status ? ` \u00b7 _${t.Status}_` : '';
    const acctTag = (isMyTasks && t.Account_Name) ? ` \u00b7 ${t.Account_Name}` : '';
    const category = t.Category ? ` \u00b7 ${t.Category}` : '';

    const taskLine = `${indicator}*${(t.Subject || 'Task').substring(0, 100)}*${owner}\n${due}${status}${acctTag}${category}`;

    const completePayload = JSON.stringify({
      action: 'complete_task',
      task_id: t.Id,
      task_subject: (t.Subject || '').substring(0, 100),
      account_name: isMyTasks ? (t.Account_Name || '') : accountName,
    });

    blocks.push({
      type: "section",
      text: { type: "mrkdwn", text: taskLine },
      accessory: {
        type: "button",
        text: { type: "plain_text", text: "\u2705 Complete", emoji: true },
        action_id: "task_complete_" + (t.Id || '').substring(0, 15),
        value: completePayload
      }
    });
  }

  if (taskList.length > maxItems) {
    blocks.push({
      type: "context",
      elements: [{ type: "mrkdwn", text: `_and ${taskList.length - maxItems} more..._` }]
    });
  }
}

if (openTasks.length > 0) {
  if (isMyTasks) {
    // Group by urgency for My Tasks view
    renderTasks(overdueTasks, ':red_circle: Overdue', 5);
    renderTasks(thisWeekTasks, ':warning: Due This Week', 5);
    renderTasks(futureTasks, 'Upcoming', 5);
  } else {
    // Single list for account view
    openTasks.sort((a, b) => {
      const dA = daysUntil(a.ActivityDate);
      const dB = daysUntil(b.ActivityDate);
      return (dA === null ? 999 : dA) - (dB === null ? 999 : dB);
    });

    blocks.push({ type: "divider" });

    for (const t of openTasks.slice(0, 10)) {
      const indicator = statusIndicator(t.ActivityDate);
      const due = dueLabel(t.ActivityDate);
      const owner = t.Owner_Name ? ` \u2014 _${t.Owner_Name}_` : '';
      const category = t.Category ? ` \u00b7 ${t.Category}` : '';
      const status = t.Status ? ` \u00b7 _${t.Status}_` : '';

      const taskLine = `${indicator}*${(t.Subject || 'Task').substring(0, 100)}*${owner}\n${due}${status}${category}`;

      const completePayload = JSON.stringify({
        action: 'complete_task',
        task_id: t.Id,
        task_subject: (t.Subject || '').substring(0, 100),
        account_name: accountName,
      });

      blocks.push({
        type: "section",
        text: { type: "mrkdwn", text: taskLine },
        accessory: {
          type: "button",
          text: { type: "plain_text", text: "\u2705 Complete", emoji: true },
          action_id: "task_complete_" + (t.Id || '').substring(0, 15),
          value: completePayload
        }
      });
    }

    if (openTasks.length > 10) {
      blocks.push({
        type: "context",
        elements: [{ type: "mrkdwn", text: `_and ${openTasks.length - 10} more..._` }]
      });
    }
  }
} else {
  blocks.push({ type: "divider" });
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: isMyTasks ? "All caught up! :tada: No open tasks." : "All caught up! :tada: No open tasks for " + accountName }
  });
}

// Completed tasks
if (completedTasks.length > 0) {
  blocks.push({ type: "divider" });
  const completedLines = completedTasks.slice(0, 5).map(t => {
    const owner = t.Owner_Name ? ` \u2014 ${t.Owner_Name}` : '';
    const acct = (isMyTasks && t.Account_Name) ? ` \u00b7 ${t.Account_Name}` : '';
    return `\u2022 ~${(t.Subject || 'Task').substring(0, 80)}~${owner}${acct}`;
  }).join('\n');
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: `*Recently Completed (${completedTasks.length})*\n${completedLines}` }
  });
}

// Footer
blocks.push({ type: "divider" });

const createPayload = JSON.stringify({
  action: 'create_task',
  account_name: isMyTasks ? '' : accountName,
  task_description: '',
  task_owner: '',
  task_owner_email: '',
  assignee_role: '',
  duration_minutes: 30,
  task_due_hint: '',
  task_category: '',
  assistant_name: assistantName,
  assistant_emoji: assistantEmoji,
});

blocks.push({
  type: "section",
  text: { type: "mrkdwn", text: "<https://glass.people.ai/sheet/514ff6d1-7e51-4bab-872e-b1f35ce13f5b|My Open Tasks> \u00b7 <https://glass.people.ai/sheet/3be9132b-cf08-4f94-9164-651bb5804e51|My Completed> \u00b7 <https://glass.people.ai/sheet/40ce97c4-0237-4afb-8d47-b10cf4792253|Last 30 Days>" },
  accessory: {
    type: "button",
    text: { type: "plain_text", text: "+ New Task", emoji: true },
    action_id: "recap_create_task_new",
    value: createPayload.substring(0, 1999)
  }
});

blocks.push({
  type: "context",
  elements: [{ type: "mrkdwn", text: isMyTasks ? "Type `tasks` to refresh \u00b7 `tasks <account>` for account-specific view" : "Type `tasks " + accountName.toLowerCase() + "` to refresh" }]
});

const overdueText = overdueTasks.length > 0 ? ', ' + overdueTasks.length + ' overdue' : '';
const notificationText = isMyTasks
  ? 'My Tasks \u2014 ' + openTasks.length + ' open' + overdueText
  : accountName + ' \u2014 ' + openTasks.length + ' open task' + (openTasks.length !== 1 ? 's' : '') + overdueText;

return [{ json: {
  blocks: JSON.stringify(blocks),
  notificationText,
  channelId,
  messageTs,
  assistantName,
  assistantEmoji,
  requestId: callbackData.requestId,
}}];

